boot.artifact:
// inferred-not-tested:默认主题规则由上游写入 artifact document.head
import { JSONEditor } from 'https://cdn.jsdelivr.net/npm/@json-editor/json-editor@2/+esm';
const el = document.getElementById('json-editor');
const editor = new JSONEditor(el, { schema: data.schema, startval: data.value ?? {}, theme: data.theme ?? 'html' });
await new Promise((resolve) => editor.on('ready', resolve));
// 结果边界读取 editor.getValue(),校验读取 editor.validate()

boot.widget:
// 上游 2.17.1 会侦测 shadow 父级并写入 shadowRoot.adoptedStyleSheets
import { JSONEditor } from 'https://cdn.jsdelivr.net/npm/@json-editor/json-editor@2/+esm';
const el = document.createElement('div'); shadowRoot.appendChild(el);
const editor = new JSONEditor(el, { schema: data.schema, startval: data.value ?? {}, theme: data.theme ?? 'html' });
await new Promise((resolve) => editor.on('ready', resolve));
// 需要现代浏览器的 constructable stylesheet 支持

